package main
import "fmt"

// This function takes a channel as an argument
func sendGreeting(ch chan string) {
    // Send the string into the channel
    ch <- "Hello from the background goroutine!"
}

func main() {
    // Create a channel that carries strings
    myChannel := make(chan string)

    // Start goroutine
    go sendGreeting(myChannel)

    // Wait to receive a message from the channel
    message := <-myChannel

    fmt.Println(message)
}
